import{_ as s,c as l,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Compatibilité : Skills Claude Code | opencode-agent-skills","description":"Découvrez comment OpenCode Agent Skills assure la compatibilité avec les skills et le système de plugins Claude Code. Maîtrisez le mécanisme de mapping d'outils, les priorités de découverte des skills, et réutilisez l'écosystème Claude existant.","frontmatter":{"title":"Compatibilité : Skills Claude Code | opencode-agent-skills","sidebarTitle":"Réutiliser les Skills Claude","subtitle":"Compatibilité avec les Skills Claude Code","description":"Découvrez comment OpenCode Agent Skills assure la compatibilité avec les skills et le système de plugins Claude Code. Maîtrisez le mécanisme de mapping d'outils, les priorités de découverte des skills, et réutilisez l'écosystème Claude existant.","tags":["Compatibilité","Claude Code","Réutilisation de skills"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"fr/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"fr/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}`),a={name:"fr/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function o(n,e,d,r,u,c){return i(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="compatibilite-avec-les-skills-claude-code" tabindex="-1">Compatibilité avec les Skills Claude Code <a class="header-anchor" href="#compatibilite-avec-les-skills-claude-code" aria-label="Permalink to &quot;Compatibilité avec les Skills Claude Code&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que vous apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que vous apprendrez&quot;">​</a></h2><ul><li>Comprendre comment le plugin assure automatiquement la compatibilité avec le format des skills Claude Code</li><li>Maîtriser le mécanisme de mapping d&#39;outils pour faire fonctionner correctement les skills Claude dans OpenCode</li><li>Connaître les règles complètes de priorité pour la découverte des skills</li><li>Réutiliser les skills existants du marketplace Claude sans avoir à les réécrire</li></ul><h2 id="votre-probleme-actuel" tabindex="-1">Votre problème actuel <a class="header-anchor" href="#votre-probleme-actuel" aria-label="Permalink to &quot;Votre problème actuel&quot;">​</a></h2><p>Vous avez déjà des skills Claude Code, ou vous souhaitez utiliser des skills du marketplace Claude, mais ces skills ont été écrits pour Claude Code. Les utiliser directement dans OpenCode pose des problèmes :</p><ul><li>Les appels d&#39;outils dans les skills Claude (comme <code>TodoWrite</code>, <code>Task</code>) n&#39;existent pas dans OpenCode</li><li>Vous ne savez pas comment faire découvrir à OpenCode les skills des plugins Claude installés</li><li>Vous craignez une incompatibilité de format et de devoir tout réécrire</li></ul><h2 id="idee-centrale" tabindex="-1">Idée centrale <a class="header-anchor" href="#idee-centrale" aria-label="Permalink to &quot;Idée centrale&quot;">​</a></h2><p>Le plugin OpenCode Agent Skills utilise un <strong>mécanisme de compatibilité à trois niveaux</strong> pour vous permettre d&#39;utiliser les skills Claude Code sans modification :</p><ol><li><strong>Découverte automatique</strong> - Analyse des skills depuis les répertoires standard de Claude Code (<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)</li><li><strong>Mapping d&#39;outils</strong> - Injection automatique d&#39;un guide de mapping lors du chargement des skills, convertissant les noms d&#39;outils Claude en noms OpenCode</li><li><strong>Support des formats</strong> - Prise en charge simultanée des formats d&#39;installation v1 et v2 des plugins Claude</li></ol><div class="info custom-block"><p class="custom-block-title">Concept clé</p><p><strong>Format des skills Claude Code</strong> - Spécification définie par Anthropic utilisant un fichier <code>SKILL.md</code> pour décrire les skills, comprenant un frontmatter YAML (métadonnées) et du contenu Markdown (instructions).</p></div><h3 id="principe-du-mapping-d-outils" tabindex="-1">Principe du mapping d&#39;outils <a class="header-anchor" href="#principe-du-mapping-d-outils" aria-label="Permalink to &quot;Principe du mapping d&#39;outils&quot;">​</a></h3><p>Lorsque le plugin détecte qu&#39;un skill chargé a été écrit pour Claude Code, il injecte automatiquement un guide de mapping :</p><table tabindex="0"><thead><tr><th>Outil Claude Code</th><th>Outil OpenCode</th><th>Règle de mapping</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>Minuscules</td></tr><tr><td><code>Task</code> (sous-agent)</td><td><code>task</code> (avec paramètre subagent_type)</td><td>Utilisation de paramètre</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>Remplacement du nom</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>Minuscules</td></tr></tbody></table><p><strong>Méthode de mapping</strong> : Le plugin injecte le guide de mapping en XML dans le contexte de session lors du chargement du skill, et l&#39;IA appelle automatiquement les bons outils selon ce mapping.</p><div class="tip custom-block"><p class="custom-block-title">Pourquoi le mapping est-il nécessaire ?</p><p>Claude Code et OpenCode utilisent des conventions de nommage différentes. Claude utilise le PascalCase (ex : <code>TodoWrite</code>), OpenCode utilise les minuscules (ex : <code>todowrite</code>). Le mapping d&#39;outils indique à l&#39;IA comment convertir les appels.</p></div><h3 id="priorite-de-decouverte-des-skills" tabindex="-1">Priorité de découverte des skills <a class="header-anchor" href="#priorite-de-decouverte-des-skills" aria-label="Permalink to &quot;Priorité de découverte des skills&quot;">​</a></h3><p>Le plugin découvre les skills dans l&#39;ordre suivant, <strong>le premier skill correspondant est utilisé</strong> (pas de duplication pour les skills de même nom) :</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Processus de découverte] --&gt; B[OpenCode niveau projet]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Claude Code niveau projet]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[OpenCode niveau utilisateur]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Claude Code niveau utilisateur]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Cache plugins Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Marketplace Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>Règles de priorité</strong> :</p><ul><li>Les skills niveau projet écrasent les skills niveau utilisateur (pour la personnalisation par projet)</li><li>Les skills OpenCode ont priorité sur les skills Claude (pour éviter la confusion)</li><li>Seule la première version découverte d&#39;un skill de même nom est conservée</li></ul><details class="details custom-block"><summary>Exemple : écrasement de skills de même nom</summary><p>Supposons que vous ayez un skill nommé <code>git-helper</code> à deux emplacements :</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (version Claude)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (version OpenCode)</li></ul><p><strong>Résultat</strong> : La version OpenCode est utilisée (priorité plus élevée)</p></details><h2 id="🎒-prerequis" tabindex="-1">🎒 Prérequis <a class="header-anchor" href="#🎒-prerequis" aria-label="Permalink to &quot;🎒 Prérequis&quot;">​</a></h2><ul><li>Plugin OpenCode Agent Skills installé et configuré</li><li>Connaissance des concepts de base des skills (lecture recommandée : <a href="./../../start/what-is-opencode-agent-skills/">Qu&#39;est-ce qu&#39;OpenCode Agent Skills ?</a>)</li><li>(Optionnel) Plugins ou skills Claude Code déjà installés</li></ul><h2 id="suivez-le-guide" tabindex="-1">Suivez le guide <a class="header-anchor" href="#suivez-le-guide" aria-label="Permalink to &quot;Suivez le guide&quot;">​</a></h2><h3 id="etape-1-verifier-que-les-skills-claude-sont-decouverts" tabindex="-1">Étape 1 : Vérifier que les skills Claude sont découverts <a class="header-anchor" href="#etape-1-verifier-que-les-skills-claude-sont-decouverts" aria-label="Permalink to &quot;Étape 1 : Vérifier que les skills Claude sont découverts&quot;">​</a></h3><p><strong>Pourquoi</strong> Confirmer que le plugin peut correctement analyser vos répertoires de skills Claude Code.</p><p>Dans OpenCode, appelez l&#39;outil :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : La liste des skills retournée inclut les skills provenant de <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>, avec le champ <code>source</code> de chaque skill indiquant sa provenance (ex : <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>Point de contrôle ✅</strong> : Confirmez que la liste contient les skills Claude attendus.</p><h3 id="etape-2-charger-un-skill-claude" tabindex="-1">Étape 2 : Charger un skill Claude <a class="header-anchor" href="#etape-2-charger-un-skill-claude" aria-label="Permalink to &quot;Étape 2 : Charger un skill Claude&quot;">​</a></h3><p><strong>Pourquoi</strong> Vérifier que le mécanisme de mapping d&#39;outils fonctionne correctement.</p><p>Appelez l&#39;outil pour charger un skill Claude :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;nom-de-votre-skill&quot;)</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : Un message de succès, comme <code>Skill &quot;xxx&quot; loaded.</code>.</p><p><strong>Point de contrôle ✅</strong> : L&#39;IA peut maintenant utiliser les instructions de ce skill.</p><h3 id="etape-3-verifier-que-le-mapping-d-outils-fonctionne" tabindex="-1">Étape 3 : Vérifier que le mapping d&#39;outils fonctionne <a class="header-anchor" href="#etape-3-verifier-que-le-mapping-d-outils-fonctionne" aria-label="Permalink to &quot;Étape 3 : Vérifier que le mapping d&#39;outils fonctionne&quot;">​</a></h3><p><strong>Pourquoi</strong> Confirmer que l&#39;IA appelle correctement les outils OpenCode et non les outils Claude.</p><p>Demandez à l&#39;IA une tâche nécessitant les outils du skill, par exemple :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utilisez la fonctionnalité todo du skill pour créer une liste de tâches.</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : L&#39;IA appelle correctement l&#39;outil <code>todowrite</code> d&#39;OpenCode, et non l&#39;outil <code>TodoWrite</code> de Claude.</p><div class="tip custom-block"><p class="custom-block-title">Comment vérifier que le mapping fonctionne ?</p><p>Consultez les logs d&#39;appels d&#39;outils de l&#39;IA (si le mode debug est activé), vous verrez qu&#39;elle appelle <code>todowrite</code> et non <code>TodoWrite</code>.</p></div><p><strong>Point de contrôle ✅</strong> : L&#39;appel d&#39;outil réussit, la tâche est accomplie.</p><h2 id="pieges-a-eviter" tabindex="-1">Pièges à éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à éviter&quot;">​</a></h2><h3 id="_1-format-de-plugin-incompatible" tabindex="-1">1. Format de plugin incompatible <a class="header-anchor" href="#_1-format-de-plugin-incompatible" aria-label="Permalink to &quot;1. Format de plugin incompatible&quot;">​</a></h3><p><strong>Problème</strong> : Les anciens plugins Claude utilisent le format v1, les nouveaux utilisent le format v2, ce qui empêche la découverte de certains skills.</p><p><strong>Cause</strong> : Les structures de <code>installed_plugins.json</code> diffèrent entre v1 et v2.</p><p><strong>Solution</strong> : Le plugin supporte les deux formats, aucune conversion manuelle n&#39;est nécessaire. Si les skills ne sont toujours pas découverts, vérifiez que <code>~/.claude/plugins/installed_plugins.json</code> existe et est correctement formaté.</p><h3 id="_2-le-mapping-d-outils-ne-fonctionne-pas" tabindex="-1">2. Le mapping d&#39;outils ne fonctionne pas <a class="header-anchor" href="#_2-le-mapping-d-outils-ne-fonctionne-pas" aria-label="Permalink to &quot;2. Le mapping d&#39;outils ne fonctionne pas&quot;">​</a></h3><p><strong>Problème</strong> : L&#39;IA appelle toujours les noms d&#39;outils Claude, provoquant des erreurs.</p><p><strong>Cause</strong> : Le contenu du skill peut contourner le guide de mapping, ou utiliser des appels d&#39;outils codés en dur.</p><p><strong>Solution</strong> :</p><ul><li>Confirmez que le skill est chargé avant utilisation, plutôt que d&#39;appeler directement les outils</li><li>Si le skill contient des exemples de code, modifiez manuellement les noms d&#39;outils au format OpenCode</li></ul><h3 id="_3-conflit-de-noms-de-skills" tabindex="-1">3. Conflit de noms de skills <a class="header-anchor" href="#_3-conflit-de-noms-de-skills" aria-label="Permalink to &quot;3. Conflit de noms de skills&quot;">​</a></h3><p><strong>Problème</strong> : Des skills de même nom existent à différents emplacements, et la mauvaise version est chargée.</p><p><strong>Cause</strong> : Écrasement dû à la priorité de découverte des skills.</p><p><strong>Solution</strong> :</p><ul><li>Vérifiez le champ <code>source</code> du skill pour confirmer sa provenance</li><li>Utilisez le format namespace pour spécifier explicitement la source : <code>use_skill(skill=&quot;user:nom-skill&quot;)</code> ou <code>use_skill(skill=&quot;claude-plugins:nom-skill&quot;)</code></li></ul><details class="details custom-block"><summary>Syntaxe des namespaces</summary><p>Le plugin supporte le format <code>namespace:nom-skill</code> :</p><ul><li><code>project:nom-skill</code> - Skill OpenCode niveau projet</li><li><code>claude-project:nom-skill</code> - Skill Claude niveau projet</li><li><code>user:nom-skill</code> - Skill OpenCode niveau utilisateur</li><li><code>claude-user:nom-skill</code> - Skill Claude niveau utilisateur</li><li><code>claude-plugins:nom-skill</code> - Skill du marketplace Claude</li></ul></details><h2 id="resume" tabindex="-1">Résumé <a class="header-anchor" href="#resume" aria-label="Permalink to &quot;Résumé&quot;">​</a></h2><p>Le plugin OpenCode Agent Skills utilise un mécanisme de compatibilité à trois niveaux pour réutiliser les skills Claude Code de manière transparente :</p><ul><li><strong>Découverte automatique</strong> - Analyse des skills depuis 6 emplacements, couvrant les niveaux projet, utilisateur et plugins</li><li><strong>Mapping d&#39;outils</strong> - Conversion automatique des noms d&#39;outils Claude en noms d&#39;outils OpenCode</li><li><strong>Support des formats</strong> - Prise en charge simultanée des formats v1 et v2 des plugins Claude</li></ul><p>Pas besoin de réécrire les skills, installez-les et utilisez-les directement, le plugin gère automatiquement les problèmes de compatibilité.</p><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons l&#39;<strong><a href="./../superpowers-integration/">Intégration du workflow Superpowers</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment activer le mode Superpowers</li><li>La détection et le chargement automatiques des skills Superpowers</li><li>Comment les workflows stricts améliorent l&#39;efficacité du développement</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir les emplacements du code source</strong></summary><blockquote><p>Mis à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Définition du mapping d&#39;outils</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>Définition des types v1/v2</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>Extraction des chemins d&#39;installation</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>Découverte des skills de plugins</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>Découverte des skills marketplace</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>Découverte des skills en cache</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>Liste des priorités de découverte</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>Logique de déduplication</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>Import de toolTranslation</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>Injection du mapping d&#39;outils</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>toolTranslation</code> : Chaîne XML du guide de mapping d&#39;outils, injectée dans le contexte de session lors du chargement des skills. Définie dans <code>src/claude.ts:19-25</code>, importée dans <code>src/tools.ts:15</code></li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>getPluginInstallPaths()</code> : Extrait les chemins d&#39;installation des plugins depuis les formats v1/v2</li><li><code>discoverSkillsFromPluginDir()</code> : Analyse le sous-répertoire skills/ du répertoire de plugins</li><li><code>discoverMarketplaceSkills()</code> : Découvre les skills depuis <code>~/.claude/plugins/marketplaces/</code> (prioritaire)</li><li><code>discoverPluginCacheSkills()</code> : Découvre les skills depuis <code>~/.claude/plugins/cache/</code> (solution de repli)</li><li><code>findFile()</code> : Recherche récursive d&#39;un fichier par nom (fonction utilitaire)</li></ul><p><strong>Flux importants</strong> :</p><ol><li>À l&#39;initialisation du plugin, <code>discoverAllSkills()</code> est appelé → parcourt les 6 chemins de découverte</li><li>Lors de la découverte des skills de plugins Claude, <code>discoverMarketplaceSkills()</code> ou <code>discoverPluginCacheSkills()</code> est appelé</li><li>Lors du chargement d&#39;un skill, l&#39;outil <code>use_skill</code> insère <code>toolTranslation</code> dans le contenu XML (ligne 244)</li></ol></details>`,68)])])}const h=s(a,[["render",o]]);export{m as __pageData,h as default};
